#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M;
        scanf("%d", &N);
        int arr1[N];
        for (int i = 0; i < N; ++i) scanf("%d", &arr1[i]);
        scanf("%d", &M);
        int arr2[M];
        for (int i = 0; i < M; ++i) scanf("%d", &arr2[i]);
        int merged[N + M];
        for (int i = 0; i < N; ++i) merged[i] = arr1[i];
        for (int i = 0; i < M; ++i) merged[N + i] = arr2[i];
        for (int i = 0; i < N + M; ++i) {
            printf("%d", merged[i]);
            if (i + 1 < N + M) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        int N, M; cin>>N;
        vector<int> arr1(N);
        for(int &x:arr1) cin>>x;
        cin>>M;
        vector<int> arr2(M);
        for(int &x:arr2) cin>>x;
        vector<int> merged; merged.reserve(N+M);
        merged.insert(merged.end(), arr1.begin(), arr1.end());
        merged.insert(merged.end(), arr2.begin(), arr2.end());
        for(size_t i=0;i<merged.size();++i){
            if(i) cout<<' ';
            cout<<merged[i];
        }
        cout<<'\n';
    }
    return 0;
}

code.Java:
import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr1 = new int[N];
            for (int i = 0; i < N; i++) arr1[i] = sc.nextInt();
            int M = sc.nextInt();
            int[] arr2 = new int[M];
            for (int i = 0; i < M; i++) arr2[i] = sc.nextInt();
            StringBuilder sb = new StringBuilder();
            for (int i = 0; i < N; i++) {
                sb.append(arr1[i]).append(' ');
            }
            for (int i = 0; i < M; i++) {
                sb.append(arr2[i]);
                if (i + 1 < M) sb.append(' ');
            }
            System.out.println(sb.toString().trim());
        }
        sc.close();
    }
}

